module dma_controller (  
    input clk,  
    input reset,  
    input start,  
    input [7:0] src_address,  
    input [7:0] dest_address,  
    output reg done  
);  
    reg [2:0] obf_state;  
    parameter IDLE = 3'b000, TRANSFER = 3'b001, COMPLETE = 3'b010;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            obf_state <= IDLE;  
            done <= 0;  
        end else begin  
            case (obf_state)  
                IDLE: begin  
                    if (start) begin  
                        obf_state <= TRANSFER;  
                        done <= 0;  
                    end  
                end  
                TRANSFER: begin  
                    // Simulate data transfer process here  
                    obf_state <= COMPLETE;  
                end  
                COMPLETE: begin  
                    done <= 1;  
                    obf_state <= IDLE;  
                end  
                default: obf_state <= IDLE;  
            endcase  
        end  
    end  
endmodule
